use actix_web::{web, App, HttpRequest, HttpResponse, HttpServer, Responder};
use reqwest::Client;
use std::net::IpAddr;
use url::Url;

async fn proxy_handler(req: HttpRequest) -> impl Responder {
    let query = req.query_string();
    let url_param = web::Query::<std::collections::HashMap<String, String>>::from_query(query)
        .unwrap_or_default()
        .get("url")
        .cloned();

    if let Some(url) = url_param {
        if let Ok(parsed_url) = Url::parse(&url) {
            if is_allowed(&parsed_url) {
                let client = Client::new();
                if let Ok(response) = client.get(parsed_url.as_str()).send().await {
                    if let Ok(body) = response.text().await {
                        return HttpResponse::Ok().body(body);
                    }
                }
            }
        }
    }
    HttpResponse::BadRequest().body("Invalid or disallowed URL")
}

fn is_allowed(url: &Url) -> bool {
    let allowlist = vec!["example.com", "api.partner.com"];
    if let Some(host) = url.host_str() {
        if allowlist.contains(&host) {
            if let Ok(ip) = host.parse::<IpAddr>() {
                return !is_private_ip(&ip);
            }
            return true;
        }
    }
    false
}

fn is_private_ip(ip: &IpAddr) -> bool {
    match ip {
        IpAddr::V4(ipv4) => ipv4.is_private() || ipv4.is_loopback(),
        IpAddr::V6(ipv6) => ipv6.is_loopback(),
    }
}

